// Generic class: T is a type parameter
public class Box<T> {
    private T item;  // Field of generic type T

    public void setItem(T item) {
        this.item = item;
    }

    public T getItem() {
        return item;
    }
}

// Generic method: swaps two elements in an array
public static <T> void swap(T[] array, int i, int j) {
    T temp = array[i];
    array[i] = array[j];
    array[j] = temp;
}

